# ============================================
# OpenClaw 一键安装脚本 (Windows PowerShell)
# ============================================
#
# 功能：自动检测系统环境，安装所需依赖，完成 OpenClaw 部署
# 支持：Windows 10/11 (需要 WSL2)
#
# 使用方法：
#   iwr -useb https://your-domain/install.ps1 | iex
#   或
#   .\install.ps1
#
# ============================================

param(
    [switch]$SkipWSL,
    [switch]$Force
)

# 配置
$NODE_MIN_VERSION = "22"
$OPENCLAW_INSTALL_URL = "https://openclaw.ai/install.ps1"

# ============================================
# 颜色输出函数
# ============================================

function Write-Info {
    param([string]$Message)
    Write-Host "[INFO] $Message" -ForegroundColor Blue
}

function Write-Success {
    param([string]$Message)
    Write-Host "[OK] $Message" -ForegroundColor Green
}

function Write-Warning {
    param([string]$Message)
    Write-Host "[WARN] $Message" -ForegroundColor Yellow
}

function Write-Error {
    param([string]$Message)
    Write-Host "[ERROR] $Message" -ForegroundColor Red
}

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host "========================================" -ForegroundColor Cyan
    Write-Host "  $Message" -ForegroundColor Cyan
    Write-Host "========================================" -ForegroundColor Cyan
    Write-Host ""
}

function Write-Banner {
    Write-Host ""

    @"

   ____                  _____          __
  / __ \____ _(_) /_____ / ___/__  ___  / /__  ____
 / /_/ / __ `/_  // __ \\__ \/ _ \/ _ \/ / _ \/ __ \
/ ____/ /_/ /_  // /_/ /__/ /  __/  __/ /  __/ /_/ /
/_/    \__,_/ /___\____/____/\___/\___/_/\___/ .___/
                                            /_/
            一键安装脚本 v1.0 (Windows)

"@ | Write-Host -ForegroundColor Cyan

    Write-Host "  支持系统: Windows 10/11 (需要 WSL2)"
    Write-Host "  核心依赖: Node.js >= $NODE_MIN_VERSION"
    Write-Host ""
}

# ============================================
# 系统检测
# ============================================

function Test-Administrator {
    $currentUser = [Security.Principal.WindowsIdentity]::GetCurrent()
    $principal = New-Object Security.Principal.WindowsPrincipal($currentUser)
    return $principal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
}

function Get-NodeVersion {
    try {
        $version = node -v 2>$null
        if ($version) {
            return $version -replace 'v', ''
        }
    } catch {}
    return "0"
}

function Compare-Version {
    param([string]$Version1, [string]$Version2)
    try {
        $v1 = [version]$Version1
        $v2 = [version]$Version2
        return $v1 -ge $v2
    } catch {
        return $false
    }
}

function Test-WSL {
    try {
        $wsl = wsl --status 2>$null
        return $true
    } catch {
        return $false
    }
}

function Test-WSL2 {
    try {
        $versions = wsl -l -v 2>$null
        return $versions -match "2"
    } catch {
        return $false
    }
}

# ============================================
# WSL 安装
# ============================================

function Install-WSL {
    Write-Step "安装 WSL2"

    if (-not (Test-Administrator)) {
        Write-Error "需要管理员权限来安装 WSL"
        Write-Info "请以管理员身份重新运行此脚本"
        Write-Info "或者手动运行: wsl --install"
        exit 1
    }

    Write-Info "正在启用 WSL 功能..."

    # 启用 WSL
    dism.exe /online /enable-feature /featurename:Microsoft-Windows-Subsystem-Linux /all /norestart

    # 启用虚拟机平台
    dism.exe /online /enable-feature /featurename:VirtualMachinePlatform /all /norestart

    Write-Info "正在安装 WSL..."
    wsl --install --no-distribution

    Write-Warning "WSL 安装完成, 但需要重启电脑"
    Write-Info "重启后请重新运行此脚本"
    exit 0
}

function Install-Ubuntu {
    Write-Step "安装 Ubuntu (WSL)"

    Write-Info "正在安装 Ubuntu..."
    wsl --install -d Ubuntu

    Write-Success "Ubuntu 安装完成"
    Write-Info "请设置 Ubuntu 用户名和密码"
    Write-Info "然后重新运行此脚本在 WSL 中安装 OpenClaw"
}

# ============================================
# Node.js 安装
# ============================================

function Install-NodeJS {
    Write-Step "安装 Node.js"

    $currentVersion = Get-NodeVersion

    if (Compare-Version $currentVersion $NODE_MIN_VERSION) {
        Write-Success "Node.js v$currentVersion 已安装 (满足要求 >= $NODE_MIN_VERSION)"
        return $true
    }

    Write-Info "当前 Node.js 版本: v$currentVersion"
    Write-Info "需要安装 Node.js >= $NODE_MIN_VERSION"

    # 检测包管理器
    $winget = Get-Command winget -ErrorAction SilentlyContinue
    $scoop = Get-Command scoop -ErrorAction SilentlyContinue
    $choco = Get-Command choco -ErrorAction SilentlyContinue

    if ($winget) {
        Write-Info "使用 winget 安装 Node.js..."
        winget install OpenJS.NodeJS.LTS --accept-package-agreements --accept-source-agreements
    } elseif ($choco) {
        Write-Info "使用 Chocolatey 安装 Node.js..."
        choco install nodejs-lts -y
    } elseif ($scoop) {
        Write-Info "使用 Scoop 安装 Node.js..."
        scoop install nodejs-lts
    } else {
        Write-Info "未检测到包管理器, 使用官方安装包..."
        Write-Info "正在下载 Node.js 安装程序..."

        $nodeUrl = "https://nodejs.org/dist/v22.12.0/node-v22.12.0-x64.msi"
        $installerPath = "$env:TEMP\node-installer.msi"

        try {
            Invoke-WebRequest -Uri $nodeUrl -OutFile $installerPath -UseBasicParsing
            Write-Info "正在启动安装程序..."
            Start-Process msiexec.exe -ArgumentList "/i `"$installerPath`" /passive /norestart" -Wait
            Remove-Item $installerPath -Force
        } catch {
            Write-Error "下载失败: $_"
            Write-Info "请手动下载安装: https://nodejs.org/"
            return $false
        }
    }

    # 刷新环境变量
    $env:Path = [System.Environment]::GetEnvironmentVariable("Path", "Machine") + ";" + [System.Environment]::GetEnvironmentVariable("Path", "User")

    # 验证安装
    $newVersion = Get-NodeVersion
    if (Compare-Version $newVersion $NODE_MIN_VERSION) {
        Write-Success "Node.js v$newVersion 安装成功"
        return $true
    } else {
        Write-Warning "Node.js 已安装, 但可能需要重启终端"
        Write-Info "请关闭并重新打开 PowerShell, 然后重新运行此脚本"
        return $false
    }
}

# ============================================
# OpenClaw 安装
# ============================================

function Install-OpenClaw {
    Write-Step "安装 OpenClaw"

    Write-Info "正在从官方源下载安装脚本..."

    try {
        # 使用官方安装脚本
        $script = Invoke-RestMethod -Uri $OPENCLAW_INSTALL_URL -UseBasicParsing
        Invoke-Expression $script

        Write-Success "OpenClaw 安装成功"
        return $true
    } catch {
        Write-Warning "官方脚本执行失败, 尝试手动安装..."
        return Install-OpenClaw-Manual
    }
}

function Install-OpenClaw-Manual {
    Write-Info "执行手动安装..."

    # 设置环境变量避免 sharp 构建问题
    $env:SHARP_IGNORE_GLOBAL_LIBVIPS = "1"

    try {
        npm install -g openclaw@latest
        Write-Success "OpenClaw 手动安装成功"
        return $true
    } catch {
        Write-Error "手动安装失败: $_"
        return $false
    }
}

# ============================================
# 验证安装
# ============================================

function Test-Installation {
    Write-Step "验证安装"

    $allOk = $true

    # 检查 Node.js
    $nodeVersion = Get-NodeVersion
    if ($nodeVersion -ne "0") {
        Write-Success "Node.js: v$nodeVersion"
    } else {
        Write-Error "Node.js: 未找到"
        $allOk = $false
    }

    # 检查 npm
    try {
        $npmVersion = npm -v 2>$null
        if ($npmVersion) {
            Write-Success "npm: $npmVersion"
        }
    } catch {
        Write-Error "npm: 未找到"
        $allOk = $false
    }

    # 检查 OpenClaw
    try {
        $openclawVersion = openclaw --version 2>$null
        if ($openclawVersion) {
            Write-Success "OpenClaw: 已安装"
        }
    } catch {
        Write-Warning "OpenClaw: 未在 PATH 中找到"
        Write-Info "可能需要重启终端"
    }

    return $allOk
}

# ============================================
# 运行新手引导
# ============================================

function Start-Onboard {
    Write-Step "运行 OpenClaw 新手引导"

    Write-Info "正在启动新手引导 (onboard)..."
    Write-Info "这将安装后台服务并完成初始化配置"
    Write-Host ""

    try {
        openclaw onboard --install-daemon
        Write-Success "新手引导完成"
    } catch {
        Write-Warning "新手引导可能需要手动完成"
        Write-Info "请稍后运行: openclaw onboard --install-daemon"
    }
}

# ============================================
# 显示完成信息
# ============================================

function Show-Complete {
    Write-Host ""
    Write-Host "========================================" -ForegroundColor Green
    Write-Host "         OpenClaw 安装完成!" -ForegroundColor Green
    Write-Host "========================================" -ForegroundColor Green
    Write-Host ""
    Write-Host "常用命令:"
    Write-Host ""
    Write-Host "  openclaw dashboard    打开仪表板"
    Write-Host "  openclaw status       查看状态"
    Write-Host "  openclaw health       健康检查"
    Write-Host "  openclaw doctor       诊断问题"
    Write-Host "  openclaw --help       查看帮助"
    Write-Host ""
    Write-Warning "提示: 如果 openclaw 命令不可用, 请重启 PowerShell"
    Write-Host ""
}

# ============================================
# WSL 模式安装
# ============================================

function Start-WSLInstall {
    Write-Step "在 WSL 中安装 OpenClaw"

    # 下载 Linux 安装脚本
    $scriptUrl = "https://openclaw.ai/install.sh"

    Write-Info "正在 WSL 中运行安装脚本..."

    # 在 WSL 中执行安装
    wsl -d Ubuntu -e bash -c "curl -fsSL $scriptUrl | bash"

    Write-Success "WSL 安装完成"
    Write-Info "请在 WSL 中运行 'openclaw onboard --install-daemon' 完成配置"
}

# ============================================
# 主函数
# ============================================

function Main {
    Write-Banner

    # 检测是否在 WSL 中
    $inWSL = $env:WSL_DISTRO_NAME -ne $null

    if ($inWSL) {
        Write-Info "检测到 WSL 环境, 执行 Linux 安装流程..."
        # 在 WSL 中应该使用 Linux 脚本
        bash -c "curl -fsSL https://openclaw.ai/install.sh | bash"
        return
    }

    # Windows 原生模式
    Write-Step "系统环境检测"

    $osVersion = [System.Environment]::OSVersion.Version
    Write-Success "操作系统: Windows $($osVersion.ToString())"

    # 检查 WSL
    if (-not $SkipWSL) {
        if (-not (Test-WSL)) {
            Write-Warning "未检测到 WSL"
            Write-Info "OpenClaw 官方推荐在 WSL2 中运行"
            Write-Host ""

            $installWSL = Read-Host "是否安装 WSL2? (推荐) [Y/n]"
            if ($installWSL -ne "n" -and $installWSL -ne "N") {
                Install-WSL
            }
        } elseif (-not (Test-WSL2)) {
            Write-Warning "检测到 WSL1, 建议升级到 WSL2"
            Write-Info "运行 'wsl --set-default-version 2' 升级"
        } else {
            Write-Success "WSL2: 已安装"

            # 询问是否在 WSL 中安装
            $useWSL = Read-Host "是否在 WSL 中安装 OpenClaw? (推荐) [Y/n]"
            if ($useWSL -ne "n" -and $useWSL -ne "N") {
                Start-WSLInstall
                return
            }
        }
    }

    # Windows 原生安装
    Write-Info "将使用 Windows 原生模式安装"
    Write-Warning "注意: Windows 原生支持可能有限, 推荐使用 WSL2"
    Write-Host ""

    # 安装 Node.js
    if (-not (Install-NodeJS)) {
        Write-Error "Node.js 安装失败, 无法继续"
        exit 1
    }

    # 安装 OpenClaw
    if (-not (Install-OpenClaw)) {
        Write-Error "OpenClaw 安装失败"
        exit 1
    }

    # 验证安装
    Test-Installation | Out-Null

    # 询问是否运行新手引导
    Write-Host ""
    $runOnboard = Read-Host "是否运行新手引导 (onboard)? [Y/n]"
    if ($runOnboard -ne "n" -and $runOnboard -ne "N") {
        Start-Onboard
    } else {
        Write-Info "跳过新手引导, 稍后可运行: openclaw onboard --install-daemon"
    }

    # 显示完成信息
    Show-Complete
}

# 运行主函数
Main
